/**
 * OPA5 List Page Object
 * Generated by ERDwithAI
 *
 * Page object for List view testing
 */

sap.ui.define(
  [
    "sap/ui/test/Opa5",
    "sap/ui/test/actions/Press",
    "sap/ui/test/actions/EnterText",
    "sap/ui/test/matchers/PropertyStrictEquals",
    "sap/ui/test/matchers/AggregationLengthEquals",
    "sap/ui/test/matchers/BindingPath",
  ],
  (Opa5, Press, EnterText, PropertyStrictEquals, AggregationLengthEquals, BindingPath) => {
    var sViewName = "List";

    Opa5.createPageObjects({
      onTheListPage: {
        viewName: sViewName,

        actions: {
          /**
           * Select an item from the list
           */
          iSelectItem: function (iIndex) {
            return this.waitFor({
              controlType: "sap.m.ColumnListItem",
              matchers: (oItem) => {
                var oTable = oItem.getParent();
                var aItems = oTable.getItems();
                return aItems.indexOf(oItem) === iIndex;
              },
              actions: new Press(),
              errorMessage: "Could not find item at index: " + iIndex,
            });
          },

          /**
           * Search for an item
           */
          iSearchFor: function (sSearchText) {
            return this.waitFor({
              controlType: "sap.m.SearchField",
              actions: new EnterText({ text: sSearchText }),
              errorMessage: "Could not find search field",
            });
          },

          /**
           * Clear the search
           */
          iClearSearch: function () {
            return this.waitFor({
              controlType: "sap.m.SearchField",
              actions: new EnterText({ text: "" }),
              errorMessage: "Could not find search field",
            });
          },

          /**
           * Press the Create button
           */
          iPressCreate: function () {
            return this.waitFor({
              controlType: "sap.m.Button",
              matchers: new PropertyStrictEquals({
                name: "text",
                value: "Create",
              }),
              actions: new Press(),
              errorMessage: "Could not find Create button",
            });
          },

          /**
           * Press the Refresh button
           */
          iPressRefresh: function () {
            return this.waitFor({
              controlType: "sap.m.Button",
              matchers: new PropertyStrictEquals({
                name: "icon",
                value: "sap-icon://refresh",
              }),
              actions: new Press(),
              errorMessage: "Could not find Refresh button",
            });
          },

          /**
           * Sort by column
           */
          iSortByColumn: function (sColumnName) {
            return this.waitFor({
              controlType: "sap.m.Column",
              matchers: new PropertyStrictEquals({
                name: "header",
                value: sColumnName,
              }),
              actions: new Press(),
              errorMessage: "Could not find column: " + sColumnName,
            });
          },
        },

        assertions: {
          /**
           * Verify the list is displayed
           */
          iShouldSeeTheList: function () {
            return this.waitFor({
              controlType: "sap.m.Table",
              success: () => {
                Opa5.assert.ok(true, "The list is displayed");
              },
              errorMessage: "Could not find the table",
            });
          },

          /**
           * Verify the list has items
           */
          iShouldSeeItems: function (iCount) {
            return this.waitFor({
              controlType: "sap.m.Table",
              matchers: new AggregationLengthEquals({
                name: "items",
                length: iCount,
              }),
              success: () => {
                Opa5.assert.ok(true, "List has " + iCount + " items");
              },
              errorMessage: "List does not have " + iCount + " items",
            });
          },

          /**
           * Verify at least one item exists
           */
          iShouldSeeAtLeastOneItem: function () {
            return this.waitFor({
              controlType: "sap.m.Table",
              matchers: (oTable) => oTable.getItems().length > 0,
              success: () => {
                Opa5.assert.ok(true, "List has at least one item");
              },
              errorMessage: "List has no items",
            });
          },

          /**
           * Verify search results
           */
          iShouldSeeSearchResults: function (sSearchText) {
            return this.waitFor({
              controlType: "sap.m.ColumnListItem",
              matchers: (oItem) => {
                var sItemText = oItem
                  .getCells()
                  .map((cell) => (cell.getText ? cell.getText() : ""))
                  .join(" ");
                return sItemText.toLowerCase().indexOf(sSearchText.toLowerCase()) > -1;
              },
              success: () => {
                Opa5.assert.ok(true, "Search results contain: " + sSearchText);
              },
              errorMessage: "Could not find search results for: " + sSearchText,
            });
          },

          /**
           * Verify no items message
           */
          iShouldSeeNoItemsMessage: function () {
            return this.waitFor({
              controlType: "sap.m.Table",
              matchers: new AggregationLengthEquals({
                name: "items",
                length: 0,
              }),
              success: () => {
                Opa5.assert.ok(true, "No items message is displayed");
              },
              errorMessage: "No items message is not displayed",
            });
          },

          /**
           * Verify create button exists
           */
          iShouldSeeCreateButton: function () {
            return this.waitFor({
              controlType: "sap.m.Button",
              matchers: new PropertyStrictEquals({
                name: "text",
                value: "Create",
              }),
              success: () => {
                Opa5.assert.ok(true, "Create button is displayed");
              },
              errorMessage: "Could not find Create button",
            });
          },
        },
      },
    });
  }
);
